import{_ as a,c as i,o as l,a1 as s}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"AI App Factory ベストプラクティスガイド：プロダクト記述、チェックポイント、スコープと反復的開発 | チュートリアル","description":"AI App Factory のベストプラクティスを習得し、AI 生成アプリの品質と効率を向上させます。明確なプロダクト記述の記述、チェックポイントによる品質制御、非目標の明確化によるスコープの肥大化防止、段階的なイテレーションによるアイデアの検証、セッション分割による Token 節約、失敗と再試行の処理方法を学びます。本チュートリアルでは、入力品質、チェックポイント確認、MVP 制御、反復開発、コンテキスト最適化、失敗処理の 6 つのテクニックを網羅します。","frontmatter":{"title":"AI App Factory ベストプラクティスガイド：プロダクト記述、チェックポイント、スコープと反復的開発 | チュートリアル","sidebarTitle":"ベストプラクティス","subtitle":"ベストプラクティス：明確な記述、チェックポイントの活用、スコープ制御と反復開発のテクニック","description":"AI App Factory のベストプラクティスを習得し、AI 生成アプリの品質と効率を向上させます。明確なプロダクト記述の記述、チェックポイントによる品質制御、非目標の明確化によるスコープの肥大化防止、段階的なイテレーションによるアイデアの検証、セッション分割による Token 節約、失敗と再試行の処理方法を学びます。本チュートリアルでは、入力品質、チェックポイント確認、MVP 制御、反復開発、コンテキスト最適化、失敗処理の 6 つのテクニックを網羅します。","tags":["ベストプラクティス","MVP","反復開発"],"prerequisite":["start-getting-started","start-pipeline-overview"],"order":200},"headers":[],"relativePath":"ja/hyz1992/agent-app-factory/faq/best-practices/index.md","filePath":"ja/hyz1992/agent-app-factory/faq/best-practices/index.md"}'),r={name:"ja/hyz1992/agent-app-factory/faq/best-practices/index.md"};function e(o,t,n,d,h,p){return l(),i("div",null,[...t[0]||(t[0]=[s(`<h1 id="ベストプラクティス-明確な記述、チェックポイントの活用、スコープ制御と反復開発のテクニック" tabindex="-1">ベストプラクティス：明確な記述、チェックポイントの活用、スコープ制御と反復開発のテクニック <a class="header-anchor" href="#ベストプラクティス-明確な記述、チェックポイントの活用、スコープ制御と反復開発のテクニック" aria-label="Permalink to &quot;ベストプラクティス：明確な記述、チェックポイントの活用、スコープ制御と反復開発のテクニック&quot;">​</a></h1><h2 id="本コースでできること" tabindex="-1">本コースでできること <a class="header-anchor" href="#本コースでできること" aria-label="Permalink to &quot;本コースでできること&quot;">​</a></h2><p>本コースを修了すると、以下のスキルを習得できます：</p><ul><li>AI に自分のアイデアを理解させるための高品質なプロダクト記述の記述方法</li><li>チェックポイントメカニズムを活用して各段階の出力品質を制御する方法</li><li>非目標を明確にしてスコープ境界を定義し、プロジェクトの肥大化を防ぐ方法</li><li>段階的なイテレーションを通じてアイデアを迅速に検証し、継続的に最適化する方法</li></ul><h2 id="今直面している課題" tabindex="-1">今直面している課題 <a class="header-anchor" href="#今直面している課題" aria-label="Permalink to &quot;今直面している課題&quot;">​</a></h2><p>以下のような状況に遭遇していませんか：</p><ul><li>「ちゃんと言ったはずなのに、生成されたのは望み通りのものではない」</li><li>「一箇所が気に入らないと、その後すべて間違っていて、修正がとても大変」</li><li>「やっているうちに機能がどんどん増えて、まったくまとまらない」</li><li>「すべての機能を一気に作ろうとして、結局何も作れなかった」</li></ul><h2 id="いつこのテクニックを使うべきか" tabindex="-1">いつこのテクニックを使うべきか <a class="header-anchor" href="#いつこのテクニックを使うべきか" aria-label="Permalink to &quot;いつこのテクニックを使うべきか&quot;">​</a></h2><p>AI App Factory を初めて使う場合でも、すでに数回経験がある場合でも、これらのベストプラクティスは以下の点で役立ちます：</p><ul><li><strong>出力品質の向上</strong>：生成されるアプリが期待通りになるようにする</li><li><strong>修正時間の節約</strong>：エラーの蓄積を防ぎ、早期に問題を発見する</li><li><strong>プロジェクト規模の制御</strong>：MVP に焦点を当て、迅速にデリバリーする</li><li><strong>開発コストの削減</strong>：段階的に検証し、無駄な投資を回避する</li></ul><h2 id="🎒-開始前の準備" tabindex="-1">🎒 開始前の準備 <a class="header-anchor" href="#🎒-開始前の準備" aria-label="Permalink to &quot;🎒 開始前の準備&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">前提条件</p><ul><li><a href="./../../start/getting-started/">クイックスタート</a> を読み、AI App Factory の基本概念を理解している</li><li><a href="./../../start/pipeline-overview/">7 段階パイプラインの概要</a> を読み、完全なプロセスを理解している</li><li>少なくとも 1 回の完全なパイプライン実行を完了している（各段階の出力を直感的に理解できるように）</li></ul></div><h2 id="コアコンセプト" tabindex="-1">コアコンセプト <a class="header-anchor" href="#コアコンセプト" aria-label="Permalink to &quot;コアコンセプト&quot;">​</a></h2><p>AI App Factory のベストプラクティスは、4 つのコア原則に基づいています：</p><ol><li><strong>入力品質が出力品質を決定する</strong>：明確で詳細なプロダクト記述は成功の第一歩</li><li><strong>チェックポイントは品質の防波堤</strong>：各段階完了後に注意深く確認し、エラーの蓄積を防ぐ</li><li><strong>MVP に集中する</strong>：非目標を明確にしてスコープを制御し、コア機能を迅速にデリバリーする</li><li><strong>継続的に反復する</strong>：最初にコアアイデアを検証し、その後段階的に機能を拡張する</li></ol><p>これらの原則はソースコードと実戦経験の要約から得られており、それらに従うことで開発効率が数倍向上します。</p><h2 id="手順通りにやってみよう" tabindex="-1">手順通りにやってみよう <a class="header-anchor" href="#手順通りにやってみよう" aria-label="Permalink to &quot;手順通りにやってみよう&quot;">​</a></h2><h3 id="テクニック-1-明確なプロダクト記述を提供する" tabindex="-1">テクニック 1：明確なプロダクト記述を提供する <a class="header-anchor" href="#テクニック-1-明確なプロダクト記述を提供する" aria-label="Permalink to &quot;テクニック 1：明確なプロダクト記述を提供する&quot;">​</a></h3><h4 id="なぜ必要か" tabindex="-1">なぜ必要か <a class="header-anchor" href="#なぜ必要か" aria-label="Permalink to &quot;なぜ必要か&quot;">​</a></h4><p>AI があなたのアイデアを理解する際、提供されたテキスト情報にしか依存できません。記述が明確であればあるほど、生成されたプロダクトは期待に近づきます。</p><h4 id="どうやるか" tabindex="-1">どうやるか <a class="header-anchor" href="#どうやるか" aria-label="Permalink to &quot;どうやるか&quot;">​</a></h4><p><strong>良いプロダクト記述には以下の要素が含まれます</strong>：</p><ul><li><strong>ターゲットユーザー</strong>：誰がこの製品を使うのか？</li><li><strong>コア課題</strong>：ユーザーはどんな困難に直面しているのか？</li><li><strong>解決策</strong>：製品はどのようにその困難を解決するのか？</li><li><strong>主要機能</strong>：どの機能を必ず含める必要があるのか？</li><li><strong>使用シーン</strong>：ユーザーはどんな状況で使うのか？</li><li><strong>制約条件</strong>：どんな制限や特別な要件があるのか？</li></ul><h4 id="比較例" tabindex="-1">比較例 <a class="header-anchor" href="#比較例" aria-label="Permalink to &quot;比較例&quot;">​</a></h4><table tabindex="0"><thead><tr><th>❌ 悪い記述</th><th>✅ 良い記述</th></tr></thead><tbody><tr><td>フィットネスアプリを作る</td><td>フィットネス初心者がトレーニングを記録できるアプリ。運動タイプ、時間、消費カロリーの記録をサポートし、今週のトレーニング統計を確認できる。ターゲットユーザーはフィットネスを始めたばかりの若者で、コア機能は素早い記録と進捗確認。ソーシャル共有や有料機能は含まない</td></tr><tr><td>家計簿アプリを作る</td><td>若者が日常支出を素早く記録できるモバイル家計簿アプリ。主な機能は金額の記録、分類の選択（食事、交通、エンタメ、その他）、今月の総支出と分類統計の確認。オフライン使用をサポートし、データはローカルにのみ保存される</td></tr><tr><td>タスク管理ツールを作る</td><td>小規模チームがタスクを管理するシンプルなツール。タスク作成、メンバー割り当て、期限設定、タスクリスト表示をサポート。チームメンバー間でタスクステータスを共有できる。複雑なワークフローや権限管理は不要</td></tr></tbody></table><h4 id="チェックポイント-✅" tabindex="-1">チェックポイント ✅ <a class="header-anchor" href="#チェックポイント-✅" aria-label="Permalink to &quot;チェックポイント ✅&quot;">​</a></h4><ul><li>[ ] 記述にターゲットユーザーが明確に示されている</li><li>[ ] 記述にユーザーが直面するコア課題が説明されている</li><li>[ ] 記述に主要機能が列挙されている（5 個以内）</li><li>[ ] 記述に制約条件や非目標が含まれている</li></ul><hr><h3 id="テクニック-2-チェックポイントで注意深く確認する" tabindex="-1">テクニック 2：チェックポイントで注意深く確認する <a class="header-anchor" href="#テクニック-2-チェックポイントで注意深く確認する" aria-label="Permalink to &quot;テクニック 2：チェックポイントで注意深く確認する&quot;">​</a></h3><h4 id="なぜ必要か-1" tabindex="-1">なぜ必要か <a class="header-anchor" href="#なぜ必要か-1" aria-label="Permalink to &quot;なぜ必要か&quot;">​</a></h4><p>パイプラインの各段階完了後にチェックポイントで一時停止し、あなたの確認を待ちます。これは<strong>品質の防波堤</strong>であり、早期に問題を発見してエラーが後続の段階に伝播するのを防ぐことができます。</p><p>この段階で問題を発見できれば、現在の段階を再実行するだけです。最後まで気づかなければ、複数の段階をロールバックする必要があり、大量の時間と Token を浪費することになります。</p><h4 id="どうやるか-1" tabindex="-1">どうやるか <a class="header-anchor" href="#どうやるか-1" aria-label="Permalink to &quot;どうやるか&quot;">​</a></h4><p><strong>各チェックポイント確認時に、以下の内容を確認します</strong>：</p><p><strong>Bootstrap 段階のチェックポイント</strong>：</p><ul><li>[ ] <code>input/idea.md</code> の問題定義が正確</li><li>[ ] ターゲットユーザーペルソナが明確で具体的</li><li>[ ] コアバリュープロポジションが明確</li><li>[ ] 仮定条件が合理的</li></ul><p><strong>PRD 段階のチェックポイント</strong>：</p><ul><li>[ ] ユーザーストーリーが明確で、受諾条件を含んでいる</li><li>[ ] 機能リストが 7 個以内（MVP 原則）</li><li>[ ] 非目標が明確に列挙されている</li><li>[ ] 技術的詳細（React、API、データベースなど）が含まれていない</li></ul><p><strong>UI 段階のチェックポイント</strong>：</p><ul><li>[ ] ページ構造が合理的で、3 ページ以内</li><li>[ ] ブラウザでプロトタイプをプレビューできる</li><li>[ ] インタラクションフローが明確</li><li>[ ] 美的スタイルが際立っている（一般的な AI スタイルを避ける）</li></ul><p><strong>Tech 段階のチェックポイント</strong>：</p><ul><li>[ ] 技術スタックの選択が合理的で、MVP 原則に合致している</li><li>[ ] データモデル設計がシンプルで、テーブル数が 10 個以内</li><li>[ ] API エンドポイントリストが完全</li><li>[ ] マイクロサービス、キャッシュなどの過度な設計が導入されていない</li></ul><p><strong>Code 段階のチェックポイント</strong>：</p><ul><li>[ ] フロントエンドとバックエンドのコード構造が完全</li><li>[ ] テストケースが含まれている</li><li>[ ] 明らかな <code>any</code> 型がない</li><li>[ ] 実行方法を説明する README.md が含まれている</li></ul><p><strong>Validation 段階のチェックポイント</strong>：</p><ul><li>[ ] 検証レポートに深刻なセキュリティ問題がない</li><li>[ ] テストカバレッジ &gt; 60%</li><li>[ ] 依存関係のインストールで競合がない</li><li>[ ] TypeScript の型チェックが通る</li></ul><p><strong>Preview 段階のチェックポイント</strong>：</p><ul><li>[ ] README.md に完全な実行説明が含まれている</li><li>[ ] Docker 設定で正常にビルドできる</li><li>[ ] ローカルでフロントエンドとバックエンドサービスを起動できる</li><li>[ ] 環境変数設定の説明が含まれている</li></ul><h4 id="チェックポイント確認フロー" tabindex="-1">チェックポイント確認フロー <a class="header-anchor" href="#チェックポイント確認フロー" aria-label="Permalink to &quot;チェックポイント確認フロー&quot;">​</a></h4><p>各チェックポイントで、システムは以下のオプションを提供します：</p><ul><li><strong>続行</strong>：出力が期待通りであれば、次の段階に進む</li><li><strong>再試行</strong>：出力に問題があれば、修正意見を提供して現在の段階を再実行する</li><li><strong>一時停止</strong>：追加情報が必要な場合やアイデアを調整したい場合、パイプラインを一時停止する</li></ul><p><strong>意思決定原則</strong>：</p><ul><li>✅ <strong>続行</strong>：すべてのチェック項目が要件を満たしている</li><li>⚠️ <strong>再試行</strong>：小さな問題（フォーマット、漏れ、詳細）で、直ちに修正できる</li><li>🛑 <strong>一時停止</strong>：重大な問題（方向が間違っている、スコープが制御不能、修正不可能）で、再計画が必要</li></ul><h4 id="落とし穴への注意" tabindex="-1">落とし穴への注意 <a class="header-anchor" href="#落とし穴への注意" aria-label="Permalink to &quot;落とし穴への注意&quot;">​</a></h4><div class="danger custom-block"><p class="custom-block-title">よくある間違い</p><p><strong>「急いで終わらせるためにチェックポイント確認をスキップしないでください！」</strong></p><p>パイプラインは「各段階で一時停止して確認する」ように設計されています。これは、問題を早期に発見するためです。習慣的に「続行」をクリックして、最後まで問題に気づかなければ、以下のことになるかもしれません：</p><ul><li>複数の段階をロールバックする</li><li>大量の作業を再実行する</li><li>大量の Token を浪費する</li></ul><p>覚えておいてください：<strong>チェックポイント確認の時間投入は、ロールバックと再実行の時間コストよりはるかに小さいです</strong>。</p></div><hr><h3 id="テクニック-3-非目標を活用してスコープを制御する" tabindex="-1">テクニック 3：非目標を活用してスコープを制御する <a class="header-anchor" href="#テクニック-3-非目標を活用してスコープを制御する" aria-label="Permalink to &quot;テクニック 3：非目標を活用してスコープを制御する&quot;">​</a></h3><h4 id="なぜ必要か-2" tabindex="-1">なぜ必要か <a class="header-anchor" href="#なぜ必要か-2" aria-label="Permalink to &quot;なぜ必要か&quot;">​</a></h4><p>**非目標（Non-Goals）は MVP 開発の中核武器です。「何をしないか」を明確に列挙することで、スコープの肥大化を効果的に防ぐことができます。</p><p>多くのプロジェクトの失敗の根源は、機能が少なすぎることではなく、機能が多すぎることです。各新機能は複雑さ、開発時間、保守コストを増加させます。境界を明確にし、コアバリューに焦点を当てることで、迅速にデリバリーできます。</p><h4 id="どうやるか-2" tabindex="-1">どうやるか <a class="header-anchor" href="#どうやるか-2" aria-label="Permalink to &quot;どうやるか&quot;">​</a></h4><p><strong>Bootstrap 段階で、非目標を明確に列挙します</strong>：</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## 非目標（本バージョンで行わない機能）</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">1.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 複数人のコラボレーションはサポートしない</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">2.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> リアルタイム同期はサポートしない</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">3.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> サードパーティサービス統合（決済、地図など）はサポートしない</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">4.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> データ分析やレポート機能は提供しない</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">5.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ソーシャル共有機能は含まない</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">6.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ユーザー認証やログイン機能は不要</span></span></code></pre></div><p><strong>PRD 段階で、非目標を独立した章にします</strong>：</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## 非目標（本バージョンで明確に行わない）</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">以下の機能は価値がありますが、今回の MVP の範囲外です：</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| 機能 | 理由 | 今後の計画 |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| --- | --- | --- |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| 複数人コラボレーション | 個人ユーザーに集中 | v2.0 で検討 |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| リアルタイム同期 | 技術的複雑さを増やす | ユーザーフィードバックが強い場合に検討 |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| 決済統合 | コアバリューではない | v1.5 で検討 |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| データ分析 | MVP には不要 | v2.0 で検討 |</span></span></code></pre></div><h4 id="非目標の判断基準" tabindex="-1">非目標の判断基準 <a class="header-anchor" href="#非目標の判断基準" aria-label="Permalink to &quot;非目標の判断基準&quot;">​</a></h4><p><strong>非目標にすべきかどうかを判断する方法</strong>：</p><ul><li>❌ この機能はコアアイデアの検証には不可欠ではない → 非目標にする</li><li>❌ この機能は技術的複雑さを大幅に増加させる → 非目標にする</li><li>❌ この機能は手動で代替できる → 非目標にする</li><li>✅ この機能は製品が存在する理由である → 必ず含める</li></ul><h4 id="落とし穴への注意-1" tabindex="-1">落とし穴への注意 <a class="header-anchor" href="#落とし穴への注意-1" aria-label="Permalink to &quot;落とし穴への注意&quot;">​</a></h4><div class="warning custom-block"><p class="custom-block-title">スコープの肥大化の罠</p><p><strong>よくあるスコープの肥大化の兆候</strong>：</p><ol><li>「どうせ簡単だから、ついでに一つ追加しよう...」</li><li>「競合はみんなこの機能を持っているから、私たちも...」</li><li>「ユーザーが必要かもしれないから、先に作っておこう...」</li><li>「この機能は面白くて、製品の目玉になる...」</li></ol><p><strong>こういうアイデアが出たとき、自分に 3 つの質問をしてください</strong>：</p><ol><li>この機能はコアアイデアの検証に役立つか？</li><li>この機能をしなくても、製品は使えるか？</li><li>この機能を追加すると、デリバリー時間が遅れるか？</li></ol><p>答えが「不要」「使える」「遅れる」なら、躊躇なく非目標にしてください。</p></div><hr><h3 id="テクニック-4-段階的に反復し、迅速に検証する" tabindex="-1">テクニック 4：段階的に反復し、迅速に検証する <a class="header-anchor" href="#テクニック-4-段階的に反復し、迅速に検証する" aria-label="Permalink to &quot;テクニック 4：段階的に反復し、迅速に検証する&quot;">​</a></h3><h4 id="なぜ必要か-3" tabindex="-1">なぜ必要か <a class="header-anchor" href="#なぜ必要か-3" aria-label="Permalink to &quot;なぜ必要か&quot;">​</a></h4><p>**MVP（最小実行可能プロダクト）のコアコンセプトは、アイデアを迅速に検証することであり、一気に完璧に作ることではありません。</p><p>反復的開発を通じて、以下のことができます：</p><ul><li>早期にユーザーフィードバックを得る</li><li>方向を適時に調整する</li><li>沈没コストを下げる</li><li>開発のモチベーションを維持する</li></ul><h4 id="どうやるか-3" tabindex="-1">どうやるか <a class="header-anchor" href="#どうやるか-3" aria-label="Permalink to &quot;どうやるか&quot;">​</a></h4><p><strong>反復的開発のステップ</strong>：</p><p><strong>第 1 ラウンド：コア機能の検証</strong></p><ol><li>AI App Factory を使用して第 1 版のアプリを生成</li><li>最もコアな 3-5 個の機能のみを含める</li><li>迅速に実行してテスト</li><li>本物のユーザーにプロトタイプを提示し、フィードバックを収集</li></ol><p><strong>第 2 ラウンド：フィードバックに基づいて最適化</strong></p><ol><li>ユーザーフィードバックに基づいて、優先度が最も高い改善点を決定</li><li><code>input/idea.md</code> または <code>artifacts/prd/prd.md</code> を修正</li><li><code>factory run &lt;stage&gt;</code> を使用して、対応する段階から再実行</li><li>新しいバージョンを生成してテスト</li></ol><p><strong>第 3 ラウンド：機能の拡張</strong></p><ol><li>コア目標に達したかどうかを評価</li><li>2-3 個の高価値機能を選択</li><li>パイプラインを通して生成して統合</li><li>継続的に反復し、段階的に改善</li></ol><h4 id="反復開発の実践例" tabindex="-1">反復開発の実践例 <a class="header-anchor" href="#反復開発の実践例" aria-label="Permalink to &quot;反復開発の実践例&quot;">​</a></h4><p><strong>シナリオ</strong>：タスク管理アプリを作りたい</p><p><strong>第 1 ラウンドの MVP</strong>：</p><ul><li>コア機能：タスク作成、リスト表示、完了マーク</li><li>非目標：メンバー管理、権限制御、リマインダー通知</li><li>デリバリー時間：1 日</li></ul><p><strong>第 2 ラウンドの最適化</strong>（フィードバックに基づく）：</p><ul><li>ユーザーフィードバック：タスクにタグを追加したい</li><li>PRD を修正し、「タグ分類」機能を追加</li><li>UI 段階からパイプラインを再実行</li><li>デリバリー時間：半日</li></ul><p><strong>第 3 ラウンドの拡張</strong>（検証成功後）：</p><ul><li>メンバー管理機能を追加</li><li>期限リマインダーを追加</li><li>タスクコメント機能を追加</li><li>デリバリー時間：2 日</li></ul><h4 id="チェックポイント-✅-1" tabindex="-1">チェックポイント ✅ <a class="header-anchor" href="#チェックポイント-✅-1" aria-label="Permalink to &quot;チェックポイント ✅&quot;">​</a></h4><p>各反復の前に、確認してください：</p><ul><li>[ ] 新機能がコア目標と一致している</li><li>[ ] 新機能にユーザーニーズの裏付けがある</li><li>[ ] 新機能が複雑さを大幅に増加させない</li><li>[ ] 明確な受諾基準がある</li></ul><hr><h2 id="上級テクニック" tabindex="-1">上級テクニック <a class="header-anchor" href="#上級テクニック" aria-label="Permalink to &quot;上級テクニック&quot;">​</a></h2><h3 id="テクニック-5-セッション分割で-token-を節約する" tabindex="-1">テクニック 5：セッション分割で Token を節約する <a class="header-anchor" href="#テクニック-5-セッション分割で-token-を節約する" aria-label="Permalink to &quot;テクニック 5：セッション分割で Token を節約する&quot;">​</a></h3><h4 id="なぜ必要か-4" tabindex="-1">なぜ必要か <a class="header-anchor" href="#なぜ必要か-4" aria-label="Permalink to &quot;なぜ必要か&quot;">​</a></h4><p>長時間パイプラインを実行するとコンテキストが蓄積し、大量の Token を消費します。<strong>セッション分割実行</strong>により、各段階がクリーンなコンテキストを独占できるようにし、使用コストを大幅に削減できます。</p><h4 id="どうやるか-4" tabindex="-1">どうやるか <a class="header-anchor" href="#どうやるか-4" aria-label="Permalink to &quot;どうやるか&quot;">​</a></h4><p><strong>各チェックポイントで「新しいセッションで続行」を選択します</strong>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 新しいコマンドラインウィンドウで実行</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">factory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> continue</span></span></code></pre></div><p>システムは自動的に以下を行います：</p><ol><li><code>.factory/state.json</code> を読み込んで状態を復元</li><li>新しい Claude Code ウィンドウを起動</li><li>次の実行待ち段階から続行</li><li>その段階に必要な入力ファイルのみをロード</li></ol><p><strong>比較</strong>：</p><table tabindex="0"><thead><tr><th>方式</th><th>長所</th><th>短所</th></tr></thead><tbody><tr><td>同一セッションで続行</td><td>シンプルで、ウィンドウを切り替える必要がない</td><td>コンテキストが蓄積し、Token 消費が大きい</td></tr><tr><td>新しいセッションで続行</td><td>各段階がクリーンなコンテキストを独占でき、Token を節約できる</td><td>ウィンドウを切り替える必要がある</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">推奨される方法</p><p>**大規模プロジェクトや Token 予算が限られている場合、「新しいセッションで続行」を強くお勧めします。</p><p>詳細は <a href="./../../advanced/context-optimization/">コンテキスト最適化</a> チュートリアルをご覧ください。</p></div><hr><h3 id="テクニック-6-失敗と再試行を処理する" tabindex="-1">テクニック 6：失敗と再試行を処理する <a class="header-anchor" href="#テクニック-6-失敗と再試行を処理する" aria-label="Permalink to &quot;テクニック 6：失敗と再試行を処理する&quot;">​</a></h3><h4 id="なぜ必要か-5" tabindex="-1">なぜ必要か <a class="header-anchor" href="#なぜ必要か-5" aria-label="Permalink to &quot;なぜ必要か&quot;">​</a></h4><p>パイプライン実行中に失敗に遭遇する可能性があります（入力不足、権限問題、コードエラーなど）。失敗の処理方法を理解することで、より迅速に進捗を回復できます。</p><h4 id="どうやるか-5" tabindex="-1">どうやるか <a class="header-anchor" href="#どうやるか-5" aria-label="Permalink to &quot;どうやるか&quot;">​</a></h4><p><strong>失敗処理のベストプラクティス</strong>（<code>failure.policy.md:267-274</code> を参照）：</p><ol><li><strong>早期に失敗する</strong>：早期に問題を発見し、後続段階での時間の浪費を防ぐ</li><li><strong>詳細なログ</strong>：問題のトラブルシューティングに十分なコンテキスト情報を記録する</li><li><strong>アトミック操作</strong>：各段階の出力はアトミックであるべきで、ロールバックしやすくする</li><li><strong>証拠を保持する</strong>：失敗したプロダクトをアーカイブしてから再試行し、比較分析を容易にする</li><li><strong>段階的な再試行</strong>：再試行時に具体的なガイダンスを提供し、単純な繰り返しを避ける</li></ol><p><strong>よくある失敗シナリオ</strong>：</p><table tabindex="0"><thead><tr><th>失敗タイプ</th><th>症状</th><th>処理方法</th></tr></thead><tbody><tr><td>出力が欠落</td><td><code>input/idea.md</code> が存在しない</td><td>再試行、書き込みパスを確認</td></tr><tr><td>スコープの肥大化</td><td>機能数 &gt; 7 個</td><td>再試行、MVP に絞り込むよう要求</td></tr><tr><td>技術エラー</td><td>TypeScript コンパイル失敗</td><td>型定義を確認して再試行</td></tr><tr><td>権限問題</td><td>Agent が未承認ディレクトリに書き込み</td><td>権限境界行列を確認</td></tr></tbody></table><p><strong>失敗回復チェックリスト</strong>：</p><ul><li>[ ] 失敗原因が明確になっている</li><li>[ ] 修正方法が実装されている</li><li>[ ] 関連設定が更新されている</li><li>[ ] 失敗した段階から再開している</li></ul><div class="tip custom-block"><p class="custom-block-title">失敗は正常です</p><p><strong>失敗を恐れないでください！</strong> AI App Factory は完全な失敗処理メカニズムを設計しています：</p><ul><li>各段階で自動的に 1 回の再試行を許可</li><li>失敗したプロダクトを自動的に <code>artifacts/_failed/</code> にアーカイブ</li><li>最近の成功したチェックポイントにロールバック可能</li></ul><p>失敗に遭遇した場合、冷静に原因を分析し、失敗戦略に従って処理してください。</p></div><hr><h2 id="本コースのまとめ" tabindex="-1">本コースのまとめ <a class="header-anchor" href="#本コースのまとめ" aria-label="Permalink to &quot;本コースのまとめ&quot;">​</a></h2><p>本コースでは、AI App Factory の 6 つのベストプラクティスを紹介しました：</p><ol><li><strong>明確なプロダクト記述</strong>：ターゲットユーザー、コア課題、主要機能、制約条件を詳細に記述</li><li><strong>チェックポイントで注意深く確認</strong>：各段階完了後に出力品質を確認し、エラーの蓄積を防ぐ</li><li><strong>非目標を活用してスコープを制御</strong>：行わない機能を明確に列挙し、スコープの肥大化を防ぐ</li><li><strong>段階的に反復</strong>：最初にコアアイデアを検証し、その後ユーザーフィードバックに基づいて段階的に拡張</li><li><strong>セッション分割で Token を節約</strong>：各チェックポイントで新しいセッションを作成し、使用コストを削減</li><li><strong>失敗を正しく処理</strong>：失敗処理メカニズムを活用し、迅速に進捗を回復</li></ol><p>これらのベストプラクティスに従うことで、AI App Factory の使用体験がよりスムーズになり、生成されるアプリの品質が高まり、開発効率が数倍向上します。</p><hr><h2 id="次回の予告" tabindex="-1">次回の予告 <a class="header-anchor" href="#次回の予告" aria-label="Permalink to &quot;次回の予告&quot;">​</a></h2><blockquote><p>次回のレッスンでは <strong><a href="./../../appendix/cli-commands/">CLI コマンドリファレンス</a></strong> を学びます。</p><p>以下の内容を学びます：</p><ul><li>factory init コマンドのすべてのパラメータとオプション</li><li>factory run コマンドで指定段階から開始する方法</li><li>factory continue コマンドで新しいセッションから続行する方法</li><li>factory status と factory list でプロジェクト情報を確認する方法</li><li>factory reset でプロジェクト状態をリセットする方法</li></ul></blockquote><hr><h2 id="付録-ソースコード参照" tabindex="-1">付録：ソースコード参照 <a class="header-anchor" href="#付録-ソースコード参照" aria-label="Permalink to &quot;付録：ソースコード参照&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの場所を表示</strong></summary><blockquote><p>更新日時：2026-01-29</p></blockquote><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>プロダクト記述のテクニック</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/README.md#L186-L210" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>186-210</td></tr><tr><td>チェックポイントメカニズム</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/agents/orchestrator.checkpoint.md#L98-L112" target="_blank" rel="noreferrer"><code>agents/orchestrator.checkpoint.md</code></a></td><td>98-112</td></tr><tr><td>非目標制御</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/README.md#L199-L203" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>199-203</td></tr><tr><td>失敗処理戦略</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/policies/failure.policy.md#L267-L274" target="_blank" rel="noreferrer"><code>policies/failure.policy.md</code></a></td><td>267-274</td></tr><tr><td>コンテキスト分離</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/policies/context-isolation.md#L10-L42" target="_blank" rel="noreferrer"><code>policies/context-isolation.md</code></a></td><td>10-42</td></tr><tr><td>コード規約</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/policies/code-standards.md" target="_blank" rel="noreferrer"><code>policies/code-standards.md</code></a></td><td>全文</td></tr></tbody></table><p><strong>重要な定数</strong>：</p><ul><li><code>MAX_RETRY_COUNT = 1</code>：各段階でデフォルトで自動的に 1 回の再試行を許可</li></ul><p><strong>重要なルール</strong>：</p><ul><li>Must Have 機能数 ≤ 7 個（MVP 原則）</li><li>ページ数 ≤ 3 ページ（UI 段階）</li><li>データモデル数 ≤ 10 個（Tech 段階）</li><li>テストカバレッジ &gt; 60%（Validation 段階）</li></ul></details>`,131)])])}const u=a(r,[["render",e]]);export{g as __pageData,u as default};
